## PowerShell script to trim the Cincinnati311.csv file to only include specific columns and replace the original file with the trimmed version.
## Included for documentation purposes and to be used in the future if needed.
$keep = @('SR_TYPE','SR_TYPE_DESC','PRIORITY','DEPT_CODE','DEPT_NAME','DEPT_DIVISION','ADDRESS','LOCATION','NEIGHBORHOOD','ZIPCODE','METHOD_RECEIVED','DATE_CREATED','TIME_RECEIVED','DATE_CLOSED','DATE_STATUS_CHANGE','TIME_STATUS_CHANGE','DATE_LAST_UPDATE','TIME_LAST_UPDATE','PLANNED_RESPONSE_TIME','PLANNED_END_DATE','PLANNED_COMPLETION_DAYS','DATE_DISPATCHED','TIME_DISPATCHED','DATE_REVISED_COMPLETION','DATE_REVISED_COMPLETION_REASON','COLLECTION_SPECIAL_DATE','COLLECTION_DAY','COLLECTION_ROUTE','COLLECTION_DIST','PROPTY_CITY_OWNED_YN','PROPTY_CITY_DEPT_OWNER','STREET_NO','STREET_DIRECTION','STREET_NAME','REQUEST_RETURN_CALL','NUM_POTHOLES','POLICE_DISTRICT','POLICE_RPT_AREA','LATITUDE','LONGITUDE','DATE_TIME_RECEIVED','COMMUNITY_COUNCIL_NEIGHBORHOOD'); Import-Csv 'data/Cincinnati311.csv' | Select-Object -Property $keep | Export-Csv 'data/Cincinnati311.trimmed.csv' -NoTypeInformation -Encoding UTF8; Move-Item 'data/Cincinnati311.trimmed.csv' 'data/Cincinnati311.csv' -Force; Write-Output 'CSV trimmed and replaced successfully.'